import{_ as a,o as t,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse(`{"title":"19. Payment Of Wages","description":"","frontmatter":{"title":"19. Payment Of Wages","eba":"Children's Services Award 2010","topics":["leave","long-service-leave","hours","overtime","wages","employment","redundancy","termination","preliminary"]},"headers":[],"relativePath":"ebas/childrens-services/wages/19-payment-of-wages.md","filePath":"ebas/childrens-services/wages/19-payment-of-wages.md"}`),r={name:"ebas/childrens-services/wages/19-payment-of-wages.md"};function s(i,e,m,p,l,d){return t(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="_19-payment-of-wages" tabindex="-1">19. Payment Of Wages <a class="header-anchor" href="#_19-payment-of-wages" aria-label="Permalink to &quot;19. Payment Of Wages&quot;">​</a></h1><ol><li><p>Except on termination of employment all wages including overtime will be paid on any day of the week other than Saturday or Sunday.</p></li><li><p>Wages may be paid weekly, fortnightly or monthly by agreement between the employer and employee, by one of the following means:</p><p>a. cash;</p><p>b. cheque; or</p><p>c. payment into employee&#39;s bank or nominated financial institution account by electronic funds transfer, without cost to the employee.</p></li><li><p>Payment on termination of employment</p></li></ol><p>a. The employer must pay an employee no later than 7 days after the day on which the employee&#39;s employment terminates:</p><pre><code>i.  the employee&#39;s wages under this award for any complete or
    incomplete pay period up to the end of the day of termination;
    and

ii. all other amounts that are due to the employee under this award
    and the
    [NES](https://www.fwc.gov.au/documents/awards/resources/nes.pdf).
</code></pre><p>a. The requirement to pay wages and other amounts under paragraph (a) is subject to further order of the Commission and the employer making deductions authorised by this award or the Act.</p><p>Note 1: Section 117(2) of the Act provides that an employer must not terminate an employee&#39;s employment unless the employer has given the employee the required minimum period of notice or &quot;has paid&quot; to the employee payment instead of giving notice.</p><p>Note 2: Paragraph (b) allows the Commission to make an order delaying the requirement to make a payment under this clause. For example, the Commission could make an order delaying the requirement to pay redundancy pay if an employer makes an application under s.120 of the Act for the Commission to reduce the amount of redundancy pay an employee is entitled to under the <a href="https://www.fwc.gov.au/documents/awards/resources/nes.pdf" target="_blank" rel="noreferrer">NES</a>.</p><p>Note 3: State and Territory long service leave laws or long service leave entitlements under s.113 of the Act, may require an employer to pay an employee for accrued long service leave on the day on which the employee&#39;s employment terminates or shortly after.</p><p>Plain language terms: pay cycle, EFT, pay slips.</p>`,9)])])}const c=a(r,[["render",s]]);export{h as __pageData,c as default};
